"""
Mock实现模块
本模块提供架构接口的Mock实现，用于开发和测试
支持Mock/真实实现一键切换，支持自定义Mock行为
"""
from typing import List, Dict, Any, Optional, UUID
from dataclasses import dataclass
from datetime import datetime
import random
import os
import json
# 响应式类型可根据项目实际使用框架替换，如RxPY的Observable等
try:
    from reactor import Mono, Flux
except ImportError:
    Mono = Any
    Flux = Any


class MockManager:
    """
    Mock管理器：统一管理Mock切换
    支持通过配置文件或环境变量一键切换Mock/真实实现
    """
    MOCK_CONFIG_PATH = os.path.join(
        os.path.dirname(os.path.abspath(__file__)),
        "..", "..", "config", "mock_config.json"
    )

    @classmethod
    def _load_config(cls) -> Dict[str, Any]:
        """加载Mock配置文件"""
        if os.path.exists(cls.MOCK_CONFIG_PATH):
            try:
                with open(cls.MOCK_CONFIG_PATH, "r", encoding="utf-8") as f:
                    return json.load(f)
            except Exception:
                pass
        return {}

    @classmethod
    def is_mock_enabled(cls, module_name: str) -> bool:
        """
        判断指定模块是否启用Mock
        :param module_name: 模块名称
        :return: 是否启用Mock
        """
        config = cls._load_config()
        module_config = config.get(module_name, {})
        return module_config.get("enabled", True)

    @classmethod
    def set_mock_mode(cls, module_name: str, enabled: bool):
        """
        设置模块的Mock模式
        :param module_name: 模块名称
        :param enabled: 是否启用Mock
        """
        config = cls._load_config()
        if module_name not in config:
            config[module_name] = {}
        config[module_name]["enabled"] = enabled
        os.makedirs(os.path.dirname(cls.MOCK_CONFIG_PATH), exist_ok=True)
        with open(cls.MOCK_CONFIG_PATH, "w", encoding="utf-8") as f:
            json.dump(config, f, ensure_ascii=False, indent=2)

    @classmethod
    def get_mock_config(cls, module_name: str) -> Dict[str, Any]:
        """
        获取模块的Mock配置
        :param module_name: 模块名称
        :return: Mock配置字典
        """
        config = cls._load_config()
        return config.get(module_name, {})


