class PredictionServiceMock:
    """预测服务Mock实现：对应submitPredictionTask、streamPredictionState接口"""
    MODULE_NAME = "prediction_service"

    def __init__(self, config: Optional[Dict[str, Any]] = None):
        self.config = config or {}
        self._mock_config = MockManager.get_mock_config(self.MODULE_NAME)

    def submitPredictionTask(self, input: PredictionCommand) -> Mono[AckResponse]:
        """提交预测任务Mock实现"""
        if self._mock_config.get("raise_error", False):
            raise RuntimeError("Mock 预测任务提交异常：服务不可用")

        fixed_value = self._mock_config.get("fixed_value")
        if fixed_value is not None:
            return Mono.just(AckResponse(**fixed_value))

        return Mono.just(AckResponse(
            code=200,
            message="任务提交成功",
            task_id=input.commandId
        ))

    def streamPredictionState(self, correlationId: UUID) -> Flux[DomainEvent]:
        """流式订阅预测状态Mock实现"""
        if self._mock_config.get("raise_error", False):
            raise RuntimeError("Mock 状态订阅异常：连接中断")

        fixed_value = self._mock_config.get("fixed_value")
        if fixed_value is not None:
            return Flux.fromIterable([DomainEvent(**item) for item in fixed_value])

        # 模拟4阶段状态变更事件流
        event_types = ["TASK_SUBMITTED", "PROCESS_CHECK_PASSED", "INFERENCE_COMPLETED", "RESULT_READY"]
        events = []
        base_ts = int(datetime.now().timestamp() * 1000)
        for i, event_type in enumerate(event_types):
            events.append(DomainEvent(
                event_id=f"evt_{random.randint(100000, 999999)}",
                event_type=event_type,
                correlation_id=correlationId,
                data={"stage": i+1, "status": "success", "progress": (i+1)*25},
                timestamp=base_ts + i * random.randint(800, 1500)
            ))
        return Flux.fromIterable(events)


